export type Category =
  | 'talismans' | 'sorceries' | 'incantations' | 'ashes-of-war'
  | 'melee-weapons' | 'ranged-weapons' | 'shields'
  | 'helm' | 'chest' | 'arms' | 'legs';

export interface Item {
  id: string;
  name: string;
  category: Category;
  subcategory?: string;
  description: string;
  effect?: string;
  location: string;
  imageFile: string;
  legendary?: boolean;
  dlc?: boolean;
  weight?: number;
  requirements?: string;
  fp?: number;
  slots?: number;
}

export function imgUrl(file: string): string {
  return `/api/img?url=${encodeURIComponent("https://eldenring.wiki.fextralife.com/file/Elden-Ring/" + file)}`;
}

